import{_ as a,o,c as i,ai as r}from"./chunks/framework.DMjte4z8.js";const d=JSON.parse('{"title":"Wait动作的陷阱：为什么你的触发器不按预期执行","description":"","frontmatter":{"title":"Wait动作的陷阱：为什么你的触发器不按预期执行","category":"triggers","updated":"2026-05-21T00:00:00.000Z","model":"openai/MiniMax-M2.7-highspeed","quality_score":0.72,"discovered_via":"gap_finder","sources":["https://www.hiveworkshop.com/threads/beginning-jass-tutorial-series.30765/","https://forum.wc3edit.net/deprotection-cheating-f64/xantan-s-recent-jass-trigger-pack-guide-t628-70.html","https://www.thehelper.net/threads/the-complete-guide-to-jass-vjass-and-cjass.122588/"]},"headers":[],"relativePath":"triggers/wait动作的陷阱为什么你的触发器不按预期执行.md","filePath":"triggers/wait动作的陷阱为什么你的触发器不按预期执行.md","lastUpdated":1779353774000}'),e={name:"triggers/wait动作的陷阱为什么你的触发器不按预期执行.md"};function n(s,t,l,g,p,u){return o(),i("div",null,[...t[0]||(t[0]=[r(`<h1 id="wait动作的陷阱-为什么你的触发器不按预期执行" tabindex="-1">Wait动作的陷阱：为什么你的触发器不按预期执行 <a class="header-anchor" href="#wait动作的陷阱-为什么你的触发器不按预期执行" aria-label="Permalink to “Wait动作的陷阱：为什么你的触发器不按预期执行”">​</a></h1><h2 id="什么是wait动作" tabindex="-1">什么是Wait动作 <a class="header-anchor" href="#什么是wait动作" aria-label="Permalink to “什么是Wait动作”">​</a></h2><p>Wait动作是触发器编辑器中最常用也最容易被误解的功能之一。简单来说，<strong>Wait就是&quot;暂停&quot;的命令</strong>——它能让触发器暂停执行一段时间，然后继续运行后面的动作。作为新手，你可能觉得&quot;等待&quot;很简单，但正是这个看似直观的动作，隐藏着许多导致触发器行为异常的陷阱。</p><h3 id="wait动作的基本原理" tabindex="-1">Wait动作的基本原理 <a class="header-anchor" href="#wait动作的基本原理" aria-label="Permalink to “Wait动作的基本原理”">​</a></h3><p>在触发器中，Wait动作位于&quot;一般&quot;分类下[^1]。当你添加Wait动作后，需要设置一个时间数值（以秒为单位）和时间类型（通常是&quot; elapsed game time&quot;即已流逝的游戏时间）。</p><p><strong>⚠️ 常见错误</strong>：很多新手把Wait理解为&quot;程序暂停X秒&quot;，但实际上触发器执行Wait时，<strong>整个触发器线程会暂停X秒</strong>。这期间同一个触发器不会再执行任何后续动作，直到等待结束。</p><p>在JASS代码层面，Wait被转换为<code>TriggerSleepAction</code>函数，它会挂起当前执行线程[^2]。这意味着每个触发器实例都有自己独立的&quot;时间线&quot;。</p><h3 id="wait与游戏时间的关系" tabindex="-1">Wait与游戏时间的关系 <a class="header-anchor" href="#wait与游戏时间的关系" aria-label="Permalink to “Wait与游戏时间的关系”">​</a></h3><p>Wait使用的是<strong>游戏时间</strong>，而不是真实时间。这意味着：</p><ol><li><strong>游戏暂停时，Wait也会暂停</strong> — 如果玩家按ESC暂停游戏，所有正在Wait的触发器都会停止计时</li><li><strong>加速/减速影响Wait</strong> — 如果你的地图有游戏速度设置，Wait的等待时间也会相应变化</li><li><strong>每个触发器实例独立计时</strong> — 同一个触发器可能被多次同时执行，每次都有自己的等待计时器</li></ol><blockquote><p><strong>💡 新手提示</strong>：如果你希望Wait不受游戏暂停影响（比如显示UI提示），需要使用其他方法，比如&quot;到期时间&quot;或定时器（Timer）系统。</p></blockquote><h3 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to “小结”">​</a></h3><p>Wait动作的本质是<strong>暂停当前触发器线程指定秒数</strong>。它依赖游戏时间运行，会随游戏暂停而暂停。理解这一点是避免后续触发器逻辑混乱的关键。在接下来的章节中，我们将深入探讨Wait为什么会引发各种意想不到的问题。</p><h2 id="wait动作的常见陷阱" tabindex="-1">Wait动作的常见陷阱 <a class="header-anchor" href="#wait动作的常见陷阱" aria-label="Permalink to “Wait动作的常见陷阱”">​</a></h2><p>在触发器中，<strong>Wait动作</strong>看起来像是&quot;暂停一下再继续&quot;，但它实际上做的事情和大多数新手想象的不一样。本节会详细解释Wait的两个核心问题，帮助你避免最常见的触发器Bug。</p><hr><h3 id="wait不会阻塞执行" tabindex="-1">Wait不会阻塞执行 <a class="header-anchor" href="#wait不会阻塞执行" aria-label="Permalink to “Wait不会阻塞执行”">​</a></h3><p>很多新手以为Wait动作会让整个触发器暂停，像电影暂停一样，等几秒后再继续播放。但实际上，<strong>Wait动作只是把你写在它下面的所有动作&quot;推迟&quot;执行，触发器本身并没有停下来</strong>。</p><p>为什么会这样？因为World Editor的触发器是基于<strong>事件驱动</strong>的。执行流程是这样的：</p><ol><li>触发器被事件激活，开始从上往下执行</li><li>执行到Wait动作时，触发器把后续动作放入<strong>待执行队列</strong></li><li>触发器本身&quot;结束&quot;了（虽然队列里还有动作）</li><li>几秒后，队列里的动作被执行，但此时<strong>已经是一个新的执行上下文</strong></li></ol><blockquote><p><strong>💡 新手提示</strong>：可以把Wait想象成&quot;写了一张延迟执行的纸条&quot;，而不是&quot;按下了暂停键&quot;。纸条写完后，你（触发器）就已经走了。</p></blockquote><p>这意味着，如果你在Wait后面有其他动作，那些动作会正常执行。所以Wait并不会&quot;阻塞&quot;任何东西。</p><hr><h3 id="单位引用在wait后失效" tabindex="-1">单位引用在Wait后失效 <a class="header-anchor" href="#单位引用在wait后失效" aria-label="Permalink to “单位引用在Wait后失效”">​</a></h3><p>这是<strong>最最最容易出错</strong>的地方，也是让无数新手崩溃的Bug来源。</p><p>当你创建一个单位变量（比如存储&quot;被攻击的单位&quot;），在Wait之前这个变量是正常的。但Wait之后，如果你尝试使用这个单位变量，你会发现单位可能：</p><ul><li>变成了&quot;null&quot;（空引用）</li><li>位置变了</li><li>甚至完全消失</li></ul><p><strong>原因</strong>：Wait会把后续动作放到一个新的执行上下文。当这些动作执行时，之前的局部变量可能已经被清理，或者单位已经被销毁（比如被杀死了）。</p><p>看一个具体例子：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>事件：单位受到攻击</span></span>
<span class="line"><span>动作：</span></span>
<span class="line"><span>    1. 设置 受伤单位 = 触发单位</span></span>
<span class="line"><span>    2. 显示文字 &quot;你受伤了！&quot;</span></span>
<span class="line"><span>    3. Wait 2.00 秒</span></span>
<span class="line"><span>    4. 移动 受伤单位 到 某区域  ← 这里可能出问题！</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>在这个例子中，第4步执行时，&quot;受伤单位&quot;这个引用很可能已经无效了——单位可能已经被杀死，或者变量已经被清空。</p><blockquote><p><strong>⚠️ 常见错误</strong>：新手常犯的错误是在Wait之前获取单位位置、属性等信息，然后在Wait之后使用这些&quot;快照&quot;。正确做法是：Wait之后如果需要使用单位，就<strong>重新获取一次</strong>单位信息，或者把需要的数据保存到<strong>临时变量</strong>中。</p></blockquote><hr><h3 id="小结-1" tabindex="-1">小结 <a class="header-anchor" href="#小结-1" aria-label="Permalink to “小结”">​</a></h3><p>Wait动作的两个核心陷阱：</p><table tabindex="0"><thead><tr><th>陷阱</th><th>说明</th></tr></thead><tbody><tr><td><strong>不阻塞执行</strong></td><td>Wait只是推迟后续动作，不是暂停整个触发器</td></tr><tr><td><strong>单位引用失效</strong></td><td>Wait后使用单位变量可能导致空引用错误</td></tr></tbody></table><p>理解这两个问题后，你就已经比大多数新手更懂触发器了！下一节我们会教你<strong>如何正确使用Wait</strong>，以及替代方案。</p><h2 id="循环变量与wait的冲突" tabindex="-1">循环变量与Wait的冲突 <a class="header-anchor" href="#循环变量与wait的冲突" aria-label="Permalink to “循环变量与Wait的冲突”">​</a></h2><p>本节将解释为什么在<strong>循环</strong>（重复执行代码的机制）中添加<strong>Wait</strong>（等待）会导致变量数值混乱，以及这种混乱如何让你的触发器做出完全错误的操作。掌握这个知识点后，你将能写出更稳定的定时循环逻辑。</p><h3 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to “操作步骤”">​</a></h3><ol><li><strong>理解问题的根源</strong> — 首先，在你的触发器中创建一个<strong>整数变量</strong>作为循环索引[^1]。这个变量在循环过程中会从1递增到5。</li><li><strong>添加Wait并观察</strong> — 在循环体内添加一个&quot;等待1秒&quot;的动作。此时请打开触发器的<strong>变量监视窗口</strong>，观察循环索引的变化。</li><li><strong>发现问题</strong> — 你会发现：第一次循环时索引是1，等待1秒后，代码继续执行时索引可能已经变成了2或更大！这就是<strong>循环索引在Wait期间的数值变化</strong>问题。</li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：新手常认为Wait会让程序&quot;暂停在那里&quot;，等1秒后继续。但实际上，WC3的触发器是<strong>单线程</strong>执行，Wait只是把这条代码&quot;放回去排队&quot;，循环本身可能继续进行！结果是当你以为在处理第1个单位时，实际在处理第5个单位。</p></blockquote><ol start="4"><li><strong>理解单位组的时序问题</strong> — 当你对<strong>单位组</strong>（多个单位的集合）使用&quot;选取单位&quot;配合Wait时，同样的问题会发生：Wait期间，其他触发器可能修改了单位组，或者循环继续导致了索引错位[^1]。</li></ol><blockquote><p><strong>💡 新手提示</strong>：解决方法是使用<strong>局部变量临时存储</strong>。在进入循环前，把当前需要的索引值或单位保存到另一个变量里，这样Wait之后你操作的仍然是&quot;快照&quot;中的数据，而不是已经变化的变量。</p></blockquote><h3 id="小结-2" tabindex="-1">小结 <a class="header-anchor" href="#小结-2" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该理解：Wait并不会&quot;冻结&quot;你的触发器，而是把执行权交出去。当你的循环配合Wait使用时，<strong>循环变量会继续变化</strong>，导致后续操作使用了错误的数值。记住&quot;快照&quot;原则——需要保持不变的值，先复制到临时变量里。</p><h2 id="wait与事件系统的冲突" tabindex="-1">Wait与事件系统的冲突 <a class="header-anchor" href="#wait与事件系统的冲突" aria-label="Permalink to “Wait与事件系统的冲突”">​</a></h2><p>本节将解释为什么在触发器中使用 Wait 动作会与事件系统产生冲突，导致你的游戏出现奇怪的行为。了解这个问题后，你就能避免在多人游戏或复杂触发器中踩坑。</p><h3 id="多触发器同时运行的问题" tabindex="-1">多触发器同时运行的问题 <a class="header-anchor" href="#多触发器同时运行的问题" aria-label="Permalink to “多触发器同时运行的问题”">​</a></h3><p>首先，你需要理解 Warcraft 3 的触发器是如何工作的。当你创建一个触发器时，它就像一个&quot;等待命令的程序&quot;。事件系统会监控游戏中的各种动作（如单位被攻击、玩家点击等），当事件发生时，对应的触发器就开始运行[^1]。</p><p>问题是：<strong>Wait 动作并不会停止整个游戏</strong>。当你使用 Wait 让一个触发器暂停时，事件系统仍然在正常运行，其他事件仍然可以触发其他触发器。这就是为什么多个触发器可能同时运行，导致难以预测的结果。</p><h3 id="事件响应被wait延迟影响" tabindex="-1">事件响应被Wait延迟影响 <a class="header-anchor" href="#事件响应被wait延迟影响" aria-label="Permalink to “事件响应被Wait延迟影响”">​</a></h3><p>当你使用 Wait 动作时，它会暂停当前触发器的执行一段时间。但此时，事件系统可能已经记录下了新的事件（比如另一个单位被点击）[^3]。如果这些事件触发了其他触发器，它们就会与原来的触发器&quot;抢着&quot;运行。</p><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常认为 Wait 会&quot;冻结&quot;游戏，让一切都停下来。实际上，Wait 只是暂停当前触发器，其他所有触发器和事件系统都在继续运行。很多地图出现&quot;单位不听使唤&quot;、&quot;技能释放混乱&quot;的问题，都是因为这个误解。</p></blockquote><h3 id="如何避免冲突" tabindex="-1">如何避免冲突 <a class="header-anchor" href="#如何避免冲突" aria-label="Permalink to “如何避免冲突”">​</a></h3><ol><li><p><strong>第一步：检查触发器结构</strong> — 在触发器编辑器中，找到使用了 Wait 动作的触发器。注意看这个触发器是否会对多个单位或多个玩家同时生效[^3]。</p></li><li><p><strong>第二步：考虑使用局部变量</strong> — 如果一个触发器可能被多次同时触发，为每次执行创建独立的局部变量，而不是依赖全局变量[^1]。</p></li><li><p><strong>第三步：使用&quot;运行中的触发器&quot;条件</strong> — 在触发器开头添加条件，检查这个触发器是否已经在运行。如果是，可以选择等待或直接退出。</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：如果你需要&quot;等待&quot;但又不想让其他触发器插入，考虑使用&quot;等待条件&quot;（Wait for Condition）并设置一个超时时间，这样可以更好地控制触发器的行为。</p></blockquote><h3 id="小结-3" tabindex="-1">小结 <a class="header-anchor" href="#小结-3" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该能够识别出哪些触发器可能因为 Wait 动作而产生冲突，并且知道如何使用局部变量和触发器条件来避免这些问题。记住：<strong>Wait 是暂停当前触发器，不是暂停整个游戏</strong>。</p><h2 id="wait的替代方案" tabindex="-1">Wait的替代方案 <a class="header-anchor" href="#wait的替代方案" aria-label="Permalink to “Wait的替代方案”">​</a></h2><p>本节将介绍三种替代Wait的方法。学完本节后，你将能够用更可靠的方式实现&quot;等待一段时间后执行&quot;的效果，再也不会被奇怪的Bug困扰！</p><h3 id="使用计时器-timer-替代wait" tabindex="-1">使用计时器(Timer)替代Wait <a class="header-anchor" href="#使用计时器-timer-替代wait" aria-label="Permalink to “使用计时器(Timer)替代Wait”">​</a></h3><p>计时器是Wait的<strong>最佳替代方案</strong>。虽然听起来复杂，但其实就像一个&quot;闹钟&quot;——设置好时间后，它会准时叫你。</p><p><strong>为什么计时器更好？</strong></p><ul><li>Wait会暂停整个触发器，计时器不会</li><li>多个计时器可以同时运行，Wait做不到</li><li>计时器执行完会精准触发回调函数</li></ul><ol><li><strong>创建计时器变量</strong> — 在变量列表（变量按钮，图标是<code>x</code>）中，点击&quot;新建变量&quot;，类型选择<code>计时器</code>，命名为<code>MyTimer</code>[^1]</li><li><strong>启动计时器</strong> — 在触发器中，找到&quot;计时器 - 启动计时器&quot;动作。设置时间为5.00秒，只执行一次</li><li><strong>创建计时器到期触发器</strong> — 新建一个触发器，添加事件：<code>计时器 - MyTimer 到期</code></li><li><strong>在到期触发器中写逻辑</strong> — 这里写你5秒后想执行的操作</li></ol><blockquote><p><strong>💡 新手提示</strong>：计时器到期后，记得在到期触发器里再次启动计时器（如果你需要循环执行的话）。别忘了这一步！</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常在一个触发器里既启动计时器又写到期逻辑。正确做法是：<strong>至少两个触发器</strong>，一个启动计时器，一个处理到期事件。</p></blockquote><h3 id="使用等待条件-wait-for-condition" tabindex="-1">使用等待条件(Wait for Condition) <a class="header-anchor" href="#使用等待条件-wait-for-condition" aria-label="Permalink to “使用等待条件(Wait for Condition)”">​</a></h3><p>如果你的触发器是在等某个&quot;条件满足&quot;，比如单位血量低于50%，那么&quot;等待条件&quot;比Wait更智能。</p><ol><li><strong>找到等待条件动作</strong> — 在触发器动作列表中，展开&quot;一般&quot;，找到<code>等待...条件为真，最多等待...秒</code></li><li><strong>设置条件和时间</strong> — 例如：等待条件为<code>单位生命值(百分比)(触发单位) &lt; 50</code>，最多等待10秒</li><li><strong>写条件检测</strong> — 在条件处使用布尔表达式，如<code>(生命值百分比(触发单位)) &lt; 50.00</code></li></ol><blockquote><p><strong>💡 新手提示</strong>：如果超时（条件没满足），触发器会继续执行下面的动作。所以记得在后面加个判断，或者用变量记录&quot;条件是否满足&quot;。</p></blockquote><h3 id="重构触发器结构避免wait" tabindex="-1">重构触发器结构避免Wait <a class="header-anchor" href="#重构触发器结构避免wait" aria-label="Permalink to “重构触发器结构避免Wait”">​</a></h3><p>这是最<strong>高级</strong>但最<strong>彻底</strong>的解决方案。思路是：不要用Wait，把&quot;等待期间做的事&quot;拆分到其他触发器里。</p><p><strong>不适合用Wait的场景</strong>：</p><ul><li>需要同时监听多个事件（攻击、受伤、死亡）</li><li>需要在等待期间响应玩家输入</li><li>等待时间超过5秒的剧情演出</li></ul><p><strong>重构思路</strong>：</p><ol><li>把原来&quot;做A → Wait → 做B&quot;的逻辑拆成两个触发器</li><li>触发器A：做A，然后启动计时器</li><li>触发器B（计时器到期）：做B</li></ol><h3 id="小结-4" tabindex="-1">小结 <a class="header-anchor" href="#小结-4" aria-label="Permalink to “小结”">​</a></h3><p>完成以上三种方法的学习后，你应该能够：</p><ul><li>✅ 用计时器替代Wait，实现精准延时</li><li>✅ 用等待条件处理&quot;等待某事发生&quot;的场景</li><li>✅ 通过重构触发器结构，优雅地避免Wait带来的问题</li></ul><blockquote><p><strong>💡 新手提示</strong>：遇到需要&quot;等一下再做什么&quot;的情况，先问自己：等待期间我需要响应其他事件吗？如果需要，果断用计时器，不用Wait！</p></blockquote><h2 id="调试wait相关问题" tabindex="-1">调试Wait相关问题 <a class="header-anchor" href="#调试wait相关问题" aria-label="Permalink to “调试Wait相关问题”">​</a></h2><p>在本节中，你将学会使用调试消息来追踪触发器的执行顺序，快速找出Wait动作导致的奇怪问题。完成学习后，你可以在游戏中实时观察触发器何时运行、变量值是多少，从而轻松定位问题根源。</p><h3 id="使用debug消息追踪执行流程" tabindex="-1">使用Debug消息追踪执行流程 <a class="header-anchor" href="#使用debug消息追踪执行流程" aria-label="Permalink to “使用Debug消息追踪执行流程”">​</a></h3><ol><li><p><strong>打开触发器编辑器</strong> — 在World Editor中点击顶部菜单的&quot;触发器&quot;（Trigger）按钮，打开触发器编辑器窗口[^1]</p></li><li><p><strong>找到需要调试的触发器</strong> — 在左侧触发器列表中找到你怀疑出问题的触发器，点击展开查看所有动作</p></li><li><p><strong>添加&quot;显示文本消息&quot;动作</strong> — 在触发器动作列表中，点击空白处选择&quot;动作&quot;→&quot;游戏&quot;→&quot;显示文本消息给玩家&quot;（或&quot;Display Text to Player&quot;）[^2]</p></li><li><p><strong>编写调试信息</strong> — 在消息框中输入包含触发器名称和关键变量值的文字，例如：<code>&quot;触发器执行！当前生命值=&quot; + (String(当前生命值))</code></p></li><li><p><strong>运行地图测试</strong> — 按F6或点击&quot;测试地图&quot;按钮，进入游戏后你就能在屏幕上方看到这些调试消息</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：调试完成后，记得删除或注释掉这些调试动作，否则正式发布时玩家会看到奇怪的文字！</p></blockquote><h3 id="常见错误案例分析" tabindex="-1">常见错误案例分析 <a class="header-anchor" href="#常见错误案例分析" aria-label="Permalink to “常见错误案例分析”">​</a></h3><p><strong>案例一：Wait之后变量变成了0</strong> 这是因为变量被其他触发器修改了，而原触发器Wait后继续使用的是旧引用。解决方法：在Wait前将变量值存入一个新的临时变量，如&quot;临时生命值 = 当前生命值&quot;，然后Wait后使用临时变量。</p><p><strong>案例二：触发器似乎跳过了某些动作</strong> 这通常是因为Wait期间，触发条件被再次触发，导致执行流程混乱。解决方法：使用&quot;触发器运行&quot;动作时启用&quot;等待完成后执行&quot;，或在触发器开头添加&quot;关闭触发器&quot;来防止重复执行[^3]。</p><p><strong>案例三：调试消息顺序混乱</strong> 这是正常现象！由于Wait会暂停当前执行，调试消息显示顺序可能与代码顺序不一致，这正好说明了Wait的异步特性。</p><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常在Wait前后打印同一个变量值，然后发现值不一样，就认为是Wait坏了。实际上，Wait只是暂停，不负责保持变量不变——变量随时可能被其他触发器修改。</p></blockquote><h3 id="小结-5" tabindex="-1">小结 <a class="header-anchor" href="#小结-5" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该能在游戏中实时观察触发器的执行流程，通过调试消息判断问题出在Wait之前还是之后。记住，调试消息是找出Wait陷阱的最佳工具——它能让你&quot;看见&quot;看不见的时间流逝。</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to “参考来源”">​</a></h2><p>[^1]: <a href="https://www.hiveworkshop.com/threads/beginning-jass-tutorial-series.30765/" target="_blank" rel="noreferrer">Beginning JASS Tutorial Series | HIVE</a> — accessed 2026-05-21 [^2]: <a href="https://forum.wc3edit.net/deprotection-cheating-f64/xantan-s-recent-jass-trigger-pack-guide-t628-70.html" target="_blank" rel="noreferrer">[Pure GUI] Xantan&#39;s RECENT Jass Trigger Pack + Guide : Map...</a> — accessed 2026-05-21 [^3]: <a href="https://www.thehelper.net/threads/the-complete-guide-to-jass-vjass-and-cjass.122588/" target="_blank" rel="noreferrer">Tutorial - The Complete Guide to JASS, vJASS, and cJASS | The Helper</a> — accessed 2026-05-21</p>`,96)])])}const c=a(e,[["render",n]]);export{d as __pageData,c as default};
